import type { PageLoad } from './$types'
import { createClient } from '$lib/gql/client'
import { gql } from 'graphql-request'

export const RUNS_QUERY = gql`
	query NodeRuns($first: Int, $after: String, $layer: RunLayer, $status: String) {
		runs(first: $first, after: $after, layer: $layer, status: $status) {
			edges {
				node {
					id
					layer
					status
					projectID
					beadId
					startedAt
					durationMs
				}
				cursor
			}
			pageInfo {
				hasNextPage
				endCursor
			}
			totalCount
		}
		projects {
			edges {
				node {
					id
					name
				}
			}
		}
	}
`

const FEDERATED_RUNS_QUERY = gql`
	query FederatedRuns($layer: RunLayer, $projectID: String) {
		federatedRuns(layer: $layer, projectID: $projectID) {
			nodeId
			projectId
			projectUrl
			writeCapability
			status
			run {
				id
				layer
				status
				projectID
				beadId
				startedAt
				durationMs
			}
		}
		projects {
			edges {
				node {
					id
					name
				}
			}
		}
	}
`

export interface RunNode {
	id: string
	layer: string
	status: string
	projectID: string | null
	beadId: string | null
	startedAt: string | null
	durationMs: number | null
}

export interface RunEdge {
	node: RunNode
	cursor: string
}

export interface PageInfo {
	hasNextPage: boolean
	endCursor: string | null
}

export interface RunConnection {
	edges: RunEdge[]
	pageInfo: PageInfo
	totalCount: number
}

interface ProjectNode {
	id: string
	name: string
}

interface QueryResult {
	runs: RunConnection
	projects: {
		edges: Array<{ node: ProjectNode }>
	}
}

export interface FederatedRunRow {
	nodeId: string
	projectId: string | null
	projectUrl: string
	writeCapability: boolean
	status: string
	run: RunNode
}

interface FederatedQueryResult {
	federatedRuns: FederatedRunRow[]
	projects: { edges: Array<{ node: ProjectNode }> }
}

export const PAGE_SIZE = 50

export const load: PageLoad = async ({ params, url, fetch }) => {
	const layer = url.searchParams.get('layer') ?? null
	const status = url.searchParams.get('status') ?? null
	const scope = url.searchParams.get('scope') === 'federation' ? 'federation' : 'local'

	const client = createClient(fetch as unknown as typeof globalThis.fetch)

	if (scope === 'federation') {
		try {
			const data = await client.request<FederatedQueryResult>(FEDERATED_RUNS_QUERY, {
				layer: layer ?? undefined
			})
			const projectNames: Record<string, string> = {}
			for (const { node } of data.projects.edges) projectNames[node.id] = node.name

			const filtered = status
				? data.federatedRuns.filter((row) => row.run.status === status)
				: data.federatedRuns

			const edges: RunEdge[] = filtered.map((row, i) => ({
				node: row.run,
				cursor: `fed:${i}`
			}))
			const federationByRunId: Record<string, FederatedRunRow> = {}
			for (const row of filtered) federationByRunId[row.run.id] = row

			return {
				nodeId: params.nodeId,
				runs: {
					edges,
					pageInfo: { hasNextPage: false, endCursor: null },
					totalCount: edges.length
				} as RunConnection,
				projects: data.projects.edges.map((e) => e.node),
				projectNames,
				activeLayer: layer,
				activeStatus: status,
				scope: 'federation' as const,
				federationByRunId,
				federationError: null as string | null
			}
		} catch (e) {
			return {
				nodeId: params.nodeId,
				runs: {
					edges: [] as RunEdge[],
					pageInfo: { hasNextPage: false, endCursor: null },
					totalCount: 0
				} as RunConnection,
				projects: [] as ProjectNode[],
				projectNames: {} as Record<string, string>,
				activeLayer: layer,
				activeStatus: status,
				scope: 'federation' as const,
				federationByRunId: {} as Record<string, FederatedRunRow>,
				federationError: (e as Error).message
			}
		}
	}

	const data = await client.request<QueryResult>(RUNS_QUERY, {
		first: PAGE_SIZE,
		layer: layer ?? undefined,
		status: status ?? undefined
	})

	const projectNames: Record<string, string> = {}
	for (const { node } of data.projects.edges) {
		projectNames[node.id] = node.name
	}

	return {
		nodeId: params.nodeId,
		runs: data.runs,
		projects: data.projects.edges.map((e) => e.node),
		projectNames,
		activeLayer: layer,
		activeStatus: status,
		scope: 'local' as const,
		federationByRunId: {} as Record<string, FederatedRunRow>,
		federationError: null as string | null
	}
}

import { createClient, type Client } from 'graphql-ws'
import { wsConnection } from '$lib/stores/connection.svelte'

// ---------------------------------------------------------------------------
// Subscription client singleton
// ---------------------------------------------------------------------------

let _subClient: Client | null = null

function resolveWsUrl(): string {
	if (typeof window === 'undefined') {
		// Node / SSR — subscriptions are client-only, so this path is never
		// reached in practice, but we provide a sensible default for testing.
		return 'ws://localhost:7743/graphql'
	}
	const proto = window.location.protocol === 'https:' ? 'wss' : 'ws'
	return `${proto}://${window.location.host}/graphql`
}

/**
 * Returns the shared graphql-ws client instance, creating it on first call.
 * Accepts an optional URL override (used in tests).
 */
export function getSubscriptionClient(urlOverride?: string): Client {
	if (!_subClient) {
		_subClient = createClient({ url: urlOverride ?? resolveWsUrl() })
		_subClient.on('connecting', () => wsConnection._onConnecting())
		_subClient.on('connected', () => wsConnection._onConnected())
		_subClient.on('closed', () => wsConnection._onClosed())
	}
	return _subClient
}

/** Tear down the singleton — call between tests or on hot-reload. */
export function disposeSubscriptionClient(): void {
	if (_subClient) {
		_subClient.dispose()
		_subClient = null
	}
	wsConnection._reset()
}

// ---------------------------------------------------------------------------
// Typed event shapes (mirror schema.graphql subscription event types)
// ---------------------------------------------------------------------------

export interface BeadEvent {
	eventID: string
	beadID: string
	/** Event kind: "created" | "status_changed" | "updated" */
	kind: string
	summary?: string | null
	body?: string | null
	actor?: string | null
	/** ISO-8601 timestamp */
	timestamp: string
}

export interface WorkerEvent {
	eventID: string
	workerID: string
	/** Execution phase: "pending" | "running" | "done" | "error" */
	phase: string
	/** ISO-8601 timestamp */
	timestamp: string
	logLine?: string | null
	beadID?: string | null
}

// ---------------------------------------------------------------------------
// subscribeBeadLifecycle
// ---------------------------------------------------------------------------

const BEAD_LIFECYCLE_SUBSCRIPTION = `
subscription BeadLifecycle($projectID: ID!) {
  beadLifecycle(projectID: $projectID) {
    eventID
    beadID
    kind
    summary
    timestamp
  }
}
`

/**
 * Subscribe to live lifecycle events for all beads in a project.
 *
 * The watcher polls beads.jsonl on disk; events arrive within ~1 s of a change.
 * Returns a dispose function — call it to unsubscribe and free resources.
 *
 * @example
 * const dispose = subscribeBeadLifecycle('/path/to/project', (evt) => {
 *   if (evt.kind === 'status_changed') updateStatus(evt.beadID, evt.summary)
 * })
 * onDestroy(dispose)
 */
export function subscribeBeadLifecycle(
	projectID: string,
	onEvent: (event: BeadEvent) => void,
	onError?: (err: unknown) => void,
	onComplete?: () => void
): () => void {
	const client = getSubscriptionClient()
	return client.subscribe(
		{ query: BEAD_LIFECYCLE_SUBSCRIPTION, variables: { projectID } },
		{
			next(data) {
				const evt = (data.data as Record<string, unknown> | null | undefined)
					?.beadLifecycle as BeadEvent | undefined
				if (evt) onEvent(evt)
			},
			error(err) {
				if (onError) {
					onError(err)
				} else {
					console.error('[ddx] beadLifecycle subscription error:', err)
				}
			},
			complete() {
				onComplete?.()
			}
		}
	)
}

// ---------------------------------------------------------------------------
// subscribeWorkerProgress
// ---------------------------------------------------------------------------

const WORKER_PROGRESS_SUBSCRIPTION = `
subscription WorkerProgress($workerID: ID!) {
  workerProgress(workerID: $workerID) {
    eventID
    workerID
    phase
    timestamp
    logLine
    beadID
  }
}
`

/**
 * Subscribe to live progress events for a given worker.
 *
 * Returns a dispose function — call it to unsubscribe and free resources.
 *
 * @example
 * const dispose = subscribeWorkerProgress('worker-123', (evt) => {
 *   logLines.push(evt.logLine ?? '')
 * })
 * onDestroy(dispose)
 */
export function subscribeWorkerProgress(
	workerID: string,
	onEvent: (event: WorkerEvent) => void,
	onError?: (err: unknown) => void,
	onComplete?: () => void
): () => void {
	const client = getSubscriptionClient()
	return client.subscribe(
		{ query: WORKER_PROGRESS_SUBSCRIPTION, variables: { workerID } },
		{
			next(data) {
				const evt = (data.data as Record<string, unknown> | null | undefined)
					?.workerProgress as WorkerEvent | undefined
				if (evt) onEvent(evt)
			},
			error(err) {
				if (onError) {
					onError(err)
				} else {
					console.error('[ddx] workerProgress subscription error:', err)
				}
			},
			complete() {
				onComplete?.()
			}
		}
	)
}

